import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.BD8VCRzL.js";const p=JSON.parse('{"title":"Dashboard Guide","description":"","frontmatter":{},"headers":[],"relativePath":"features/dashboard.md","filePath":"features/dashboard.md"}'),i={name:"features/dashboard.md"};function r(n,e,l,h,u,g){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="dashboard-guide" tabindex="-1">Dashboard Guide <a class="header-anchor" href="#dashboard-guide" aria-label="Permalink to &quot;Dashboard Guide&quot;">​</a></h1><p>Your dashboard shows everything about your trading session in one screen. No clicking around, no navigating to different pages. Here is what you are looking at.</p><h2 id="the-layout" tabindex="-1">The Layout <a class="header-anchor" href="#the-layout" aria-label="Permalink to &quot;The Layout&quot;">​</a></h2><p>The dashboard has four main sections:</p><ol><li><strong>P&amp;L Chart</strong> — The largest chart, at the top</li><li><strong>Discipline Score</strong> — Smaller chart, left side</li><li><strong>Agency Score</strong> — Smaller chart, right side</li><li><strong>Session Insights</strong> — Panel at the bottom</li></ol><p>There is also a warning bar that appears at the top when the system detects potentially problematic patterns.</p><h2 id="p-l-chart-cumulative-profit-loss" tabindex="-1">P&amp;L Chart (Cumulative Profit/Loss) <a class="header-anchor" href="#p-l-chart-cumulative-profit-loss" aria-label="Permalink to &quot;P&amp;L Chart (Cumulative Profit/Loss)&quot;">​</a></h2><p>This is the biggest chart on your dashboard. It shows your running total P&amp;L over the session.</p><p><strong>What you see:</strong></p><ul><li>A line chart with the X-axis showing trade sequence (Trade #1, Trade #2, etc.)</li><li>The Y-axis showing dollar amounts</li><li>A dashed horizontal line at $0 — the breakeven reference</li><li>A gray dotted line showing your average P&amp;L per trade</li></ul><p><strong>How to read it:</strong></p><ul><li><strong>Green line:</strong> You are in profit overall</li><li><strong>Red line:</strong> You are down overall</li><li><strong>Blue line:</strong> Mixed — some wins, some losses</li></ul><p><strong>Hovering over any point</strong> shows a tooltip with:</p><ul><li>Trade number</li><li>Timestamp</li><li>Individual trade P&amp;L</li><li>Cumulative P&amp;L</li><li>Direction (long or short)</li><li>Your discipline and agency scores for that trade</li></ul><p><strong>A note on extreme values:</strong> If a trade P&amp;L is unusually large (way above or below normal), the tooltip flags it so you can see what drove big swings.</p><div class="tip custom-block"><p class="custom-block-title">Watch the Slope</p><p>The angle of the line tells you a lot. A steep upward slope means you are hitting winners. A flat or downward slope means the session is tough. Use this to gauge how the day is going at a glance.</p></div><h2 id="discipline-score-chart" tabindex="-1">Discipline Score Chart <a class="header-anchor" href="#discipline-score-chart" aria-label="Permalink to &quot;Discipline Score Chart&quot;">​</a></h2><p>This chart tracks your trading discipline over time.</p><p><strong>What you see:</strong></p><ul><li>A step chart (it looks like stairs going up or down)</li><li>Green dots for +1 scores</li><li>Red dots for -1 scores</li><li>Gray dots for 0 scores</li><li>A dashed horizontal line at 0</li></ul><p><strong>What it measures:</strong></p><ul><li><strong>+1:</strong> You followed your rules, waited for your setup, traded your plan</li><li><strong>0:</strong> Neutral — the trade was neither especially disciplined nor undisciplined</li><li><strong>-1:</strong> You deviated — chased, overtraded, ignored your rules</li></ul><p>The chart shows a running sum, not individual scores. So if you get +1, -1, +1, your line goes up, down, then up again.</p><p><strong>Toggle the 3-Trade Average:</strong></p><p>There is a button above the chart that lets you overlay a 3-trade moving average. This smooths out the noise and shows you the trend in your discipline. Turn it on to see if you are generally getting more or less disciplined as the session progresses.</p><h2 id="agency-score-chart" tabindex="-1">Agency Score Chart <a class="header-anchor" href="#agency-score-chart" aria-label="Permalink to &quot;Agency Score Chart&quot;">​</a></h2><p>This chart tracks whether you are trading with intention or reacting emotionally.</p><p><strong>What you see:</strong></p><ul><li>Same format as the Discipline chart — step chart with colored dots</li><li>Green for +1, red for -1, gray for 0</li></ul><p><strong>What it measures:</strong></p><ul><li><strong>+1:</strong> You made an intentional decision — you chose to enter, you chose to exit</li><li><strong>0:</strong> Neutral</li><li><strong>-1:</strong> You reacted emotionally — revenge trading, FOMO, fear, frustration</li></ul><p><strong>Why this matters:</strong></p><p>Agency is about control. A trade can be disciplined (you followed your rules) but still lack agency (you took the trade because you were angry about the last loss). Both scores matter.</p><h2 id="session-insights-panel" tabindex="-1">Session Insights Panel <a class="header-anchor" href="#session-insights-panel" aria-label="Permalink to &quot;Session Insights Panel&quot;">​</a></h2><p>This panel shows summary stats and, after enough trades, AI-generated insights.</p><p><strong>Before 5 trades:</strong></p><ul><li>It shows a message encouraging you to keep logging trades</li><li>Basic stats: total trades, win rate, net discipline</li></ul><p><strong>After 5 trades:</strong></p><ul><li>Full stats appear: total trades, win rate, net discipline</li><li>AI insights start showing up (see the <a href="./ai-insights">AI Insights</a> guide for details)</li></ul><h2 id="warning-bar" tabindex="-1">Warning Bar <a class="header-anchor" href="#warning-bar" aria-label="Permalink to &quot;Warning Bar&quot;">​</a></h2><p>Above the charts, you might see a colored warning bar.</p><p><strong>Amber warning (yellow):</strong></p><ul><li>Appears after 3 consecutive discipline -1 scores OR 3 consecutive agency -1 scores</li><li>The bar is yellow with a warning icon</li><li>It tells you which trades triggered the warning</li></ul><p><strong>Orange warning:</strong></p><ul><li>Appears after 4+ consecutive discipline -1 scores OR 4+ consecutive agency -1 scores</li><li>The bar is orange</li><li>This is a stronger signal that you might be tilted</li></ul><p><strong>What to do:</strong></p><p>The warning is not a punishment. It is a mirror. If you see it, take a breath. Step back. The system is not judging you — it is just pointing out a pattern.</p><div class="warning custom-block"><p class="custom-block-title">The Warning Is Not Interrupting</p><p>The warning appears at the top of your dashboard but does not stop you from logging more trades. You decide whether to keep trading or take a break.</p></div><h2 id="empty-states" tabindex="-1">Empty States <a class="header-anchor" href="#empty-states" aria-label="Permalink to &quot;Empty States&quot;">​</a></h2><p>When you first log in with no trades:</p><ul><li>The P&amp;L chart shows a placeholder encouraging you to log trades</li><li>The Discipline and Agency charts show the same</li><li>The Insights panel asks you to log trades to unlock insights</li></ul><p>This is normal. Once you log your first trade, the charts start populating.</p><h2 id="session-stats-summary" tabindex="-1">Session Stats Summary <a class="header-anchor" href="#session-stats-summary" aria-label="Permalink to &quot;Session Stats Summary&quot;">​</a></h2><p>At a glance, you can see:</p><ul><li><strong>Total Trades:</strong> How many trades you have logged this session</li><li><strong>Win Rate:</strong> Percentage of winning trades</li><li><strong>Net Discipline:</strong> Sum of all discipline scores (positive = more disciplined than not)</li><li><strong>Net Agency:</strong> Sum of all agency scores (positive = more intentional than reactive)</li></ul><p>These update in real time as you log trades.</p><h2 id="viewing-past-sessions" tabindex="-1">Viewing Past Sessions <a class="header-anchor" href="#viewing-past-sessions" aria-label="Permalink to &quot;Viewing Past Sessions&quot;">​</a></h2><p>In the current version, the dashboard shows only today&#39;s session. If you want to review past days, look for the session history feature or export your data for analysis.</p><hr><p>That is your dashboard. At a glance, you can see how much money you are making, how disciplined you are being, and whether you are trading with intention. Use it to stay aware throughout your session.</p>',60)])])}const c=t(i,[["render",r]]);export{p as __pageData,c as default};
